def process_data(data, role=None):
    """Helper function to clean and standardize data."""
    name = data.get("name", "").strip().lower()
    email = data.get("email", "").strip().lower().replace(" ", "")

    if not name or not email:
        return None

    result = {
        "name": name,
        "email": email
    }
    if role:
        result["role"] = role
    return result

def process_user(data):
    """Processes general user data."""
    return process_data(data, role=None)

def process_admin(data):
    """Processes admin user data, adding the 'admin' role."""
    return process_data(data, role="admin")

